('news','header','title','Новости'),
('news','header','subtitle','Всё самое важное из жизни радио'),
('news','articles','items','[{"id":1,"date":"26 апреля","category":"Анонс","title":"Радио Генезия запускает новую волну летних хитов","text":"С 1 мая стартует обновлённое летнее расписание. Новые рубрики, свежие треки и специальные эфиры каждый выходной."},{"id":2,"date":"24 апреля","category":"Конкурс","title":"Победители апрельского конкурса объявлены","text":"Объявляем победителей розыгрыша апреля. Поздравляем счастливчиков — с вами свяжутся в ближайшие дни."},{"id":3,"date":"22 апреля","category":"Новости","title":"Новый ведущий в утреннем эфире — уже в мае","text":"Команду пополняет новый голос. Познакомьтесь с ведущим в нашем Telegram-канале."},{"id":4,"date":"18 апреля","category":"Технологии","title":"Обновление потока: теперь 320 kbps","text":"Улучшили качество трансляции. Слушайте в максимальном качестве на сайте и в приложениях."},{"id":5,"date":"15 апреля","category":"Интервью","title":"Интервью с DJ Phantom: о нейромузыке и будущем","text":"Поговорили с резидентом о трендах электронной музыки и о том, что нас ждёт в эфире."},{"id":6,"date":"10 апреля","category":"Анонс","title":"Совместный эфир с Радио Космос — 5 мая","text":"Специальный совместный выпуск. Два радио, один поток, лучшие треки двух аудиторий."}]'),
