('contests','items','list','[{"id":1,"status":"active","title":"Весенний голос","description":"Запиши кавер на любой трек из нашего плейлиста и пришли аудиофайл на почту. Лучший войдёт в эфир!","deadline":"До 15 мая","prize":"10 000 ₽"},{"id":2,"status":"active","title":"Угадай мелодию","description":"Каждый день в 12:00 в эфире — фрагмент трека. Кто первым напишет правильный ответ в Telegram — получает приз!","deadline":"Ежедневно","prize":"Мерч радио"},{"id":3,"status":"soon","title":"Лето в эфире","description":"Пришли свой летний трек-лист. Лучшая подборка попадёт в эфир на целый день, а автор получит приз.","deadline":"Старт 1 июня","prize":"Билеты на фестиваль"},{"id":4,"status":"ended","title":"Апрельский розыгрыш","description":"Конкурс завершён. Победители выбраны случайным образом среди всех участников.","deadline":"Завершён","prize":"2 билета на концерт"}]'),
